from datetime import datetime
import hashlib
import hmac

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str
    metadata: Dict[str, any] = None
    
    def to_dict(self):
        return {
            'id': self.id,
            'name': self.name,
            'type': self.type,
            'value': self.value,
            'owner_id': self.owner_id,
            'metadata': self.metadata or {}
        }

@dataclass
class Player:
    id: str
    username: str
    session_id: str
    items: List[str]
    last_seen: datetime
    
    def to_dict(self):
        return {
            'id': self.id,
            'username': self.username,
            'items': self.items,
            'last_seen': self.last_seen.isoformat()
        }

class SecureInventoryManager:
    def __init__(self, secret_key: str):
        self.secret_key = secret_key.encode() if isinstance(secret_key, str) else secret_key
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.websocket_connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.lock = asyncio.Lock()
        
    def generate_signature(self, data: str, timestamp: str) -> str:
        """Generate HMAC signature for request verification"""
        message = f"{data}{timestamp}".encode()
        signature = hmac.new(self.secret_key, message, hashlib.sha256).hexdigest()
        return signature
    
    def verify_signature(self, data: str, timestamp: str, signature: str) -> bool:
        """Verify HMAC signature"""
        expected_signature = self.generate_signature(data, timestamp)
        return hmac.compare_digest(signature, expected_signature)
    
    async def authenticate_player(self, websocket, auth_data: Dict) -> Optional[str]:
        """Authenticate player and return player ID"""
        try:
            player_id = auth_data.get('player_id')
            timestamp = auth_data.get('timestamp')
            signature = auth_data.get('signature')
            
            if not all([player_id, timestamp, signature]):
                return None
                
            # Verify signature
            if not self.verify_signature(json.dumps(auth_data), timestamp, signature):
                return None
                
            # Check if player exists
            if player_id not in self.players:
                return None
                
            # Update last seen
            self.players[player_id].last_seen = datetime.now()
            
            # Store websocket connection
            self.websocket_connections[player_id] = websocket
            
            return player_id
            
        except Exception as e:
            logger.error(f"Authentication failed: {e}")
            return None
    
    async def create_player(self, player_id: str, username: str, session_id: str) -> bool:
        """Create a new player"""
        async with self.lock:
            if player_id in self.players:
                return False
                
            self.players[player_id] = Player(
                id=player_id,
                username=username,
                session_id=session_id,
                items=[],
                last_seen=datetime.now()
            )
            return True
    
    async def add_item(self, item: Item) -> bool:
        """Add item to inventory system"""
        async with self.lock:
            if item.id in self.items:
                return False
            self.items[item.id] = item
            if item.owner_id in self.players:
                self.players[item.owner_id].items.append(item.id)
            return True
    
    async def transfer_item(self, item_id: str, from_player_id: str, to_player_id: str) -> bool:
        """Transfer item from one player to another"""
        async with self.lock:
            # Validate item exists
            if item_id not in self.items:
                return False
                
            item = self.items[item_id]
            
            # Validate ownership
            if item.owner_id != from_player_id:
                return False
                
            # Validate players exist
            if from_player_id not in self.players or to_player_id not in self.players:
                return False
                
            # Perform transfer
            item.owner_id = to_player_id
            self.players[from_player_id].items.remove(item_id)
            self.players[to_player_id].items.append(item_id)
            
            return True
    
    async def get_player_inventory(self, player_id: str) -> List[Dict]:
        """Get player's inventory"""
        async with self.lock:
            if player_id not in self.players:
                return []
                
            inventory = []
            for item_id in self.players[player_id].items:
                if item_id in self.items:
                    inventory.append(self.items[item_id].to_dict())
            return inventory
    
    async def get_item_details(self, item_id: str) -> Optional[Dict]:
        """Get item details"""
        async with self.lock:
            if item_id in self.items:
                return self.items[item_id].to_dict()
            return None
    
    async def broadcast_item_update(self, item_id: str, player_id: str):
        """Broadcast item ownership update to relevant players"""
        try:
            item = self.items.get(item_id)
            if not item:
                return
                
            # Notify both players
            if item.owner_id in self.websocket_connections:
                await self.websocket_connections[item.owner_id].send(
                    json.dumps({
                        'type': 'item_update',
                        'item_id': item_id,
                        'owner_id': item.owner_id,
                        'timestamp': datetime.now().isoformat()
                    })
                )
                
            if player_id in self.websocket_connections:
                await self.websocket_connections[player_id].send(
                    json.dumps({
                        'type': 'item_update',
                        'item_id': item_id,
                        'owner_id': item.owner_id,
                        'timestamp': datetime.now().isoformat()
                    })
                )
                
        except Exception as e:
            logger.error(f"Broadcast error: {e}")

class MMOGameServer:
    def __init__(self, secret_key: str = "default_secret_key"):
        self.inventory_manager = SecureInventoryManager(secret_key)
        self.active_connections: Set[websockets.WebSocketServerProtocol] = set()
        
    async def handle_client(self, websocket: websockets.WebSocketServerProtocol, path: str):
        """Handle individual client connections"""
        try:
            self.active_connections.add(websocket)
            logger.info(f"New client connected: {websocket.remote_address}")
            
            async for message in websocket:
                try:
                    data = json.loads(message)
                    response = await self.process_message(websocket, data)
                    if response:
                        await websocket.send(json.dumps(response))
                except json.JSONDecodeError:
                    await websocket.send(json.dumps({'error': 'Invalid JSON'}))
                except Exception as e:
                    logger.error(f"Message processing error: {e}")
                    await websocket.send(json.dumps({'error': 'Internal server error'}))
                    
        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Client disconnected: {websocket.remote_address}")
        except Exception as e:
            logger.error(f"Connection error: {e}")
        finally:
            self.active_connections.discard(websocket)
    
    async def process_message(self, websocket: websockets.WebSocketServerProtocol, data: Dict) -> Optional[Dict]:
        """Process incoming messages from clients"""
        message_type = data.get('type')
        player_id = data.get('player_id')
        
        if message_type == 'authenticate':
            authenticated_player_id = await self.inventory_manager.authenticate_player(websocket, data)
            if authenticated_player_id:
                return {
                    'type': 'auth_success',
                    'player_id': authenticated_player_id,
                    'timestamp': datetime.now().isoformat()
                }
            else:
                return {'type': 'auth_failed', 'error': 'Authentication failed'}
                
        elif message_type == 'get_inventory':
            if not player_id:
                return {'error': 'Player ID required'}
            inventory = await self.inventory_manager.get_player_inventory(player_id)
            return {
                'type': 'inventory_response',
                'items': inventory,
                'timestamp': datetime.now().isoformat()
            }
            
        elif message_type == 'trade_request':
            item_id = data.get('item_id')
            from_player_id = data.get('from_player_id')
            to_player_id = data.get('to_player_id')
            
            if not all([item_id, from_player_id, to_player_id]):
                return {'error': 'Missing required fields'}
                
            success = await self.inventory_manager.transfer_item(item_id, from_player_id, to_player_id)
            if success:
                await self.inventory_manager.broadcast_item_update(item_id, from_player_id)
                return {
                    'type': 'trade_success',
                    'item_id': item_id,
                    'from_player_id': from_player_id,
                    'to_player_id': to_player_id,
                    'timestamp': datetime.now().isoformat()
                }
            else:
                return {'type': 'trade_failed', 'error': 'Trade failed'}
                
        elif message_type == 'item_details':
            item_id = data.get('item_id')
            if not item_id:
                return {'error': 'Item ID required'}
            details = await self.inventory_manager.get_item_details(item_id)
            if details:
                return {
                    'type': 'item_details_response',
                    'item': details,
                    'timestamp': datetime.now().isoformat()
                }
            else:
                return {'type': 'item_not_found', 'error': 'Item not found'}
                
        elif message_type == 'create_player':
            player_id = data.get('player_id')
            username = data.get('username')
            session_id = data.get('session_id')
            
            if not all([player_id, username, session_id]):
                return {'error': 'Missing required fields'}
                
            success = await self.inventory_manager.create_player(player_id, username, session_id)
            if success:
                return {
                    'type': 'player_created',
                    'player_id': player_id,
                    'timestamp': datetime.now().isoformat()
                }
            else:
                return {'type': 'player_creation_failed', 'error': 'Player already exists'}
                
        elif message_type == 'add_item':
            item_data = data.get('item')
            if not item_data:
                return {'error': 'Item data required'}
                
            try:
                item = Item(
                    id=item_data['id'],
                    name=item_data['name'],
                    type=item_data['type'],
                    value=item_data['value'],
                    owner_id=item_data['owner_id'],
                    metadata=item_data.get('metadata')
                )
                success = await self.inventory_manager.add_item(item)
                if success:
                    return {
                        'type': 'item_added',
                        'item_id': item.id,
                        'timestamp': datetime.now().isoformat()
                    }
                else:
                    return {'type': 'item_add_failed', 'error': 'Item already exists'}
            except Exception as e:
                return {'type': 'item_add_failed', 'error': str(e)}
                
        return {'error': 'Unknown message type'}
    
    async def start_server(self, host: str = 'localhost', port: int = 8765):
        """Start the game server"""
        server = await websockets.serve(
            self.handle_client,
            host,
            port,
            ping_interval=30,
            ping_timeout=10
        )
        logger.info(f"Server started on {host}:{port}")
        await server.wait_closed()

